#include <stdio.h>
#include <stdlib.h>
#define MAX_N 5000
#define MAX_T 500

// Structure to represent a tree node
typedef struct Node {
    int id;
    int numChildren;
    struct Node** children;
    double expectedSteps;
} Node;

// Function to create a new tree node
Node* createNode(int id) {
    Node* node = (Node*) malloc(sizeof(Node));
    node->id = id;
    node->numChildren = 0;
    node->children = NULL;
    node->expectedSteps = 0.0;
    return node;
}

// Function to add a child to a node
void addChild(Node* node, Node* child) {
    node->numChildren++;
    node->children = (Node**) realloc(node->children, node->numChildren * sizeof(Node*));
    node->children[node->numChildren - 1] = child;
}

// Function to calculate the expected number of steps for a node
void calculateExpectedSteps(Node* node) {
    if (node->numChildren == 0) {
        node->expectedSteps = 1.0;
    } else {
        double sum = 0.0;
        for (int i = 0; i < node->numChildren; i++) {
            calculateExpectedSteps(node->children[i]);
            sum += node->children[i]->expectedSteps;
        }
        node->expectedSteps = 1.0 + sum / node->numChildren;
    }
}

int main() {
    int t;
    scanf("%d", &t);
    for (int i = 0; i < t; i++) {
        int n;
        scanf("%d", &n);
        Node** nodes = (Node**) malloc(n * sizeof(Node*));
        for (int j = 0; j < n; j++) {
            nodes[j] = createNode(j);
        }
        for (int j = 0; j < n - 1; j++) {
            int u, v;
            scanf("%d %d", &u, &v);
            u--;
            v--;
            addChild(nodes[u], nodes[v]);
            addChild(nodes[v], nodes[u]);
        }
        for (int j = 0; j < n; j++) {
            calculateExpectedSteps(nodes[j]);
        }
        for (int j = 0; j < n; j++) {
            printf("%.10f ", nodes[j]->expectedSteps);
        }
        printf("\n");
        for (int j = 0; j < n; j++) {
            free(nodes[j]->children);
            free(nodes[j]);
        }
        free(nodes);
    }
    return 0;
}

