    } else {
        double sum = 0.0;
        for (int i = 0; i < node->children.size(); i++) {
            calculateExpectedSteps(node->children[i]);
            sum += node->children[i]->expectedSteps;
        }
        node->expectedSteps = 1.0 + sum / node->children.size();
    }
}

