import java.util.ArrayList;
import java.util.Scanner;

public class Main {
    // Structure to represent a tree node
    static class Node {
        int id;
        ArrayList<Node> children;
        double expectedSteps;

        public Node(int id) {
            this.id = id;
            this.children = new ArrayList<>();
            this.expectedSteps = 0.0;
        }
    }

    // Function to add a child to a node
    public static void addChild(Node node, Node child) {
        node.children.add(child);
    }

    // Function to calculate the expected number of steps for a node
    public static void calculateExpectedSteps(Node node) {
        if (node.children.isEmpty()) {
            node.expectedSteps = 1.0;
        } else {
            double sum = 0.0;
            for (Node child : node.children) {
                calculateExpectedSteps(child);
                sum += child.expectedSteps;
            }
            node.expectedSteps = 1.0 + sum / node.children.size();
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        for (int i = 0; i < t; i++) {
            int n = scanner.nextInt();
            Node[] nodes = new Node[n];
            for (int j = 0; j < n; j++) {
                nodes[j] = new Node(j);
            }
            for (int j = 0; j < n - 1; j++) {
                int u = scanner.nextInt() - 1;
                int v = scanner.nextInt() - 1;
                addChild(nodes[u], nodes[v]);
                addChild(nodes[v], nodes[u]);
            }
            for (int j = 0; j < n; j++) {
                calculateExpectedSteps(nodes[j]);
            }
            for (int j = 0; j < n; j++) {
                System.out.print(nodes[j].expectedSteps + " ");
            }
            System.out.println();
        }
    }
}

