function calculate_expected_steps(node) {
    if (node.children.length === 0) {
        node.expectedSteps = 1.0;
    } else {
        let sum = 0.0;
        for (let child of node.children) {
            calculate_expected_steps(child);
            sum += child.expectedSteps;
        }
        node.expectedSteps = 1.0 + sum / node.children.length;
    }
}

